// budget.js - Minified budget management module
let currentBudgets=[];
async function fetchBudgets(){try{const response=await fetchWithAuth(`${CONFIG.API_BASE_URL}${CONFIG.API_ENDPOINTS.BUDGETS}`,{method:'GET'});if(response.ok){const budgets=await response.json();currentBudgets=Array.isArray(budgets)?budgets:[];displayBudgets(currentBudgets);return currentBudgets;}else{console.error('Failed to fetch budgets:',response.status);showToast('Failed to load budgets','error');return[];}}catch(error){console.error('Error fetching budgets:',error);showToast('Network error. Please check your connection.','error');return[];}}
async function createBudget(budgetData){const submitBtn=document.querySelector('#budgetForm button[type="submit"]');if(submitBtn){submitBtn.disabled=true;submitBtn.textContent='Creating...';}
try{const response=await fetchWithAuth(`${CONFIG.API_BASE_URL}${CONFIG.API_ENDPOINTS.BUDGETS}`,{method:'POST',body:JSON.stringify({category:budgetData.category,amount:parseFloat(budgetData.amount),start_date:budgetData.start_date,end_date:budgetData.end_date,spent:0})});if(response.ok){const newBudget=await response.json();showToast('Budget created successfully!','success');await fetchBudgets();resetBudgetForm();return newBudget;}else{showToast('Failed to create budget','error');return null;}}catch(error){console.error('Error creating budget:',error);showToast('Network error','error');return null;}finally{if(submitBtn){submitBtn.disabled=false;submitBtn.textContent='Create Budget';}}}
async function updateBudget(budgetId,budgetData){try{const response=await fetchWithAuth(`${CONFIG.API_BASE_URL}${CONFIG.API_ENDPOINTS.BUDGETS}${budgetId}/`,{method:'PUT',body:JSON.stringify(budgetData)});if(response.ok){const updatedBudget=await response.json();showToast('Budget updated successfully!','success');await fetchBudgets();return updatedBudget;}else{showToast('Failed to update budget','error');return null;}}catch(error){console.error('Error updating budget:',error);showToast('Network error','error');return null;}}
async function deleteBudget(budgetId){if(!confirm('Are you sure you want to delete this budget?'))return;try{const response=await fetchWithAuth(`${CONFIG.API_BASE_URL}${CONFIG.API_ENDPOINTS.BUDGETS}${budgetId}/`,{method:'DELETE'});if(response.ok){showToast('Budget deleted successfully!','success');await fetchBudgets();return true;}else{showToast('Failed to delete budget','error');return false;}}catch(error){console.error('Error deleting budget:',error);showToast('Network error','error');return false;}}
function displayBudgets(budgets){const container=document.getElementById('budgetsList');if(!container)return;if(!budgets||budgets.length===0){container.innerHTML='<p>No budgets created yet.</p>';return;}
container.innerHTML=budgets.map(budget=>{const progress=(budget.spent/budget.amount)*100;const progressClass=progress>80?'danger':progress>60?'warning':'success';return`
<div class="budget-card">
<div class="budget-header">
<h3>${budget.category}</h3>
<span class="budget-status ${progressClass}">${progress.toFixed(1)}%</span>
</div>
<div class="budget-details">
<div class="budget-amount">
<span>$${budget.spent.toFixed(2)}</span>
<span>of $${budget.amount.toFixed(2)}</span>
</div>
<div class="progress-bar">
<div class="progress-fill ${progressClass}" style="width: ${Math.min(progress,100)}%"></div>
</div>
<div class="budget-dates">
<small>${formatDate(budget.start_date)} - ${formatDate(budget.end_date)}</small>
</div>
</div>
<div class="budget-actions">
<button onclick="editBudget(${budget.id})" class="btn btn-sm btn-secondary">Edit</button>
<button onclick="deleteBudget(${budget.id})" class="btn btn-sm btn-danger">Delete</button>
</div>
</div>
`;}).join('');}
function resetBudgetForm(){const form=document.getElementById('budgetForm');if(form){form.reset();}}
function editBudget(budgetId){const budget=currentBudgets.find(b=>b.id===budgetId);if(!budget)return;const form=document.getElementById('budgetForm');if(form){document.getElementById('budgetId').value=budget.id;document.getElementById('category').value=budget.category;document.getElementById('amount').value=budget.amount;document.getElementById('start_date').value=budget.start_date;document.getElementById('end_date').value=budget.end_date;document.querySelector('#budgetForm button[type="submit"]').textContent='Update Budget';}}
function formatDate(dateString){const date=new Date(dateString);return date.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});}
if(document.getElementById('budgetForm')){document.getElementById('budgetForm').addEventListener('submit',async function(e){e.preventDefault();const budgetId=document.getElementById('budgetId').value;const budgetData={category:document.getElementById('category').value,amount:document.getElementById('amount').value,start_date:document.getElementById('start_date').value,end_date:document.getElementById('end_date').value};if(budgetId){await updateBudget(budgetId,budgetData);}else{await createBudget(budgetData);}});}
if(window.location.pathname.includes('budget.html')){document.addEventListener('DOMContentLoaded',fetchBudgets);}
